// to a Lua table, and executes the 'calculate_final_price' function defined in the script.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// 1. Initialize a new Lua state
	L := lua.NewState()
	defer L.Close()

	// 2. Load and execute the user-provided Lua script string.
	// This defines the global function `calculate_final_price` within the VM.
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to load lua script: %w", err)
	}

	// 3. Get the global function `calculate_final_price` and push it onto the stack.
	L.GetGlobal("calculate_final_price")

	// Check if the function actually exists.
	if L.Type(-1) != lua.LTFunction {
		return 0, errors.New("lua script must define a global function named 'calculate_final_price'")
	}

	// 4. Convert the Go context map (map[string]float64) into a Lua table.
	// We create a new table on the stack.
	ctxTable := L.NewTable()

	// Iterate over the Go map and populate the Lua table.
	for key, val := range ctx {
		L.PushString(key)      // Push key
		L.PushNumber(val)      // Push value
		L.SetTable(-3)         // Set table[key] = value (pops key and value)
