	}

	// 6. Retrieve the result from the stack.
	// The result should be at the top of the stack (-1).
	if L.Type(-1) == lua.LTNumber {
		val := L.ToNumber(-1)
		return float64(val), nil
	}

	return 0, errors.New("lua function 'calculate_final_price' did not return a number")
