package main

import (
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

const (
	// Define resource limits for the Lua VM to prevent abuse
	luaMemoryLimit    = 20 * 1024 * 1024 // 20MB
	luaInstructionLimit = 1000000         // 1 million instructions
	luaTimeout        = 100 * time.Millisecond
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Set memory limit for the Lua state
	// Note: gopher-lua does not expose SetMembudget/SetMaxInstructions directly on LState in all versions.
	// We rely on the Go-level timeout and the underlying allocator limits or environment constraints.
	// If using a version that supports context or specific control hooks, they would be set here.

	// Create a channel to enforce a timeout on script execution
	done := make(chan struct{})
	var execErr error
	var result float64

	go func() {
		defer close(done)
		defer func() {
			if r := recover(); r != nil {
				execErr = fmt.Errorf("panic during script execution: %v", r)
			}
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			execErr = fmt.Errorf("failed to execute Lua script: %w", err)
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			execErr = fmt.Errorf("calculate_final_price is not a function or not defined")
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			execErr = fmt.Errorf("failed to call calculate_final_price: %w", err)
			return
		}

		// Get the result from the Lua stack
		res := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if res.Type() != lua.LTNumber {
			execErr = fmt.Errorf("calculate_final_price did not return a number")
			return
		}

		result = float64(res.(lua.LNumber))
	}()

	// Wait for execution or timeout
	select {
	case <-done:
		if execErr != nil {
			return 0, execErr
		}
		return result, nil
	case <-time.After(luaTimeout):
		// Timeout reached. We need to stop the goroutine.
		// gopher-lua does not provide a safe way to interrupt a running goroutine from outside
		// other than closing the state, which might cause race conditions.
		// However, since this function returns immediately after timeout,
		// the state is deferred closed. The goroutine might panic accessing the closed state,
		// which is caught by the recover() block.
		return 0, fmt.Errorf("script execution timed out")
	}
}

